import { describe, expect, it } from "vitest";

import { chunkMessagesForEmbedding, factEmbeddingText, selectBackfillCandidates } from "./embeddingsEngine";

function msg(id: string, role: string, content: string) {
  return { id, role, content };
}

describe("chunkMessagesForEmbedding", () => {
  it("returns no chunks for no messages", () => {
    expect(chunkMessagesForEmbedding([])).toEqual([]);
  });

  it("folds up to 6 messages into one chunk keyed by the first message id", () => {
    const messages = Array.from({ length: 6 }, (_, i) => msg(`m${i}`, "user", `krátká ${i}`));
    const chunks = chunkMessagesForEmbedding(messages);
    expect(chunks).toHaveLength(1);
    expect(chunks[0].refId).toBe("m0");
  });

  it("starts a new chunk after 6 messages", () => {
    const messages = Array.from({ length: 8 }, (_, i) => msg(`m${i}`, "user", `krátká ${i}`));
    const chunks = chunkMessagesForEmbedding(messages);
    expect(chunks).toHaveLength(2);
    expect(chunks[1].refId).toBe("m6");
  });

  it("splits early when the char cap is reached", () => {
    const long = "x".repeat(1600);
    const chunks = chunkMessagesForEmbedding([msg("a", "user", long), msg("b", "assistant", "ok")]);
    expect(chunks).toHaveLength(2);
    expect(chunks[0].refId).toBe("a");
    expect(chunks[1].refId).toBe("b");
  });

  it("labels roles as Hráč/Vypravěč", () => {
    const [chunk] = chunkMessagesForEmbedding([
      msg("a", "user", "Vytáhnu krystal."),
      msg("b", "assistant", "Krystal se rozzáří."),
    ]);
    expect(chunk.text).toContain("Hráč: Vytáhnu krystal.");
    expect(chunk.text).toContain("Vypravěč: Krystal se rozzáří.");
  });
});

describe("selectBackfillCandidates", () => {
  it("drops the last verbatimWindow messages", () => {
    const messages = Array.from({ length: 10 }, (_, i) => msg(`m${i}`, "user", `${i}`));
    const result = selectBackfillCandidates(messages, 4);
    expect(result.map((m) => m.id)).toEqual(["m0", "m1", "m2", "m3", "m4", "m5"]);
  });

  it("filters out non user/assistant roles", () => {
    const messages = [msg("a", "system", "sys"), msg("b", "user", "hi"), msg("c", "assistant", "hey")];
    const result = selectBackfillCandidates(messages, 0);
    expect(result.map((m) => m.id)).toEqual(["b", "c"]);
  });

  it("returns empty when history is shorter than the window", () => {
    const messages = Array.from({ length: 3 }, (_, i) => msg(`m${i}`, "user", `${i}`));
    expect(selectBackfillCandidates(messages, 20)).toEqual([]);
  });
});

describe("factEmbeddingText", () => {
  it("is deterministic and includes category/subject", () => {
    expect(factEmbeddingText({ category: "event", subject: "Krystal", fact: "Nalezen v lese." })).toBe(
      "(event/Krystal) Nalezen v lese.",
    );
  });
});

import { execute, query } from "../database";

interface SettingRow {
  key: string;
  value: string;
}

export async function getSetting(key: string): Promise<string | null> {
  const rows = await query<SettingRow>("SELECT key, value FROM settings WHERE key = $1", [key]);
  return rows[0]?.value ?? null;
}

export async function setSetting(key: string, value: string): Promise<void> {
  await execute(
    `INSERT INTO settings (key, value) VALUES ($1, $2)
     ON CONFLICT (key) DO UPDATE SET value = excluded.value`,
    [key, value],
  );
}

export async function getAllSettings(): Promise<Record<string, string>> {
  const rows = await query<SettingRow>("SELECT key, value FROM settings", []);
  return Object.fromEntries(rows.map((r) => [r.key, r.value]));
}

import { useEffect, useState } from "react";
import { useTranslation } from "react-i18next";

import { getSetting, setSetting } from "../../db/repositories/settingsRepo";
import {
  DEFAULT_MEMORY_MIN_SCORE,
  DEFAULT_MEMORY_TOP_K,
} from "../../memory/embeddingsEngine";
import { DEFAULT_EXTRACTION_INTERVAL } from "../../memory/memoryEngine";
import { DEFAULT_VERBATIM_WINDOW } from "../../prompt/promptBuilder";
import { FieldHelp } from "../common/FieldHelp";

const inputStyle = {
  backgroundColor: "var(--color-surface-2)",
  borderColor: "var(--color-border-strong)",
  color: "var(--color-text)",
} as const;

/** Global defaults for the memory engine (plan §7 M5): how often ledger
 * extraction runs, and how many recent messages stay verbatim in the
 * prompt before being folded into the summary. Per-chat overrides (the
 * extraction connection) live in the chat room header, next to the persona
 * picker, since they're tied to a specific chat rather than app-wide. */
export function MemorySettingsPanel() {
  const { t } = useTranslation(["settings", "common"]);
  const [extractionInterval, setExtractionInterval] = useState(String(DEFAULT_EXTRACTION_INTERVAL));
  const [verbatimWindow, setVerbatimWindow] = useState(String(DEFAULT_VERBATIM_WINDOW));
  const [embeddingModel, setEmbeddingModel] = useState("");
  const [topK, setTopK] = useState(String(DEFAULT_MEMORY_TOP_K));
  const [minScore, setMinScore] = useState(String(DEFAULT_MEMORY_MIN_SCORE));
  const [saved, setSaved] = useState(false);

  useEffect(() => {
    void (async () => {
      const [interval, window, model, k, score] = await Promise.all([
        getSetting("extraction_interval"),
        getSetting("verbatim_window"),
        getSetting("embedding_model"),
        getSetting("memory_top_k"),
        getSetting("memory_min_score"),
      ]);
      if (interval) setExtractionInterval(interval);
      if (window) setVerbatimWindow(window);
      if (model) setEmbeddingModel(model);
      if (k) setTopK(k);
      if (score) setMinScore(score);
    })();
  }, []);

  const handleSave = async () => {
    const interval = Math.max(1, Number(extractionInterval) || DEFAULT_EXTRACTION_INTERVAL);
    const window = Math.max(4, Number(verbatimWindow) || DEFAULT_VERBATIM_WINDOW);
    const k = Math.max(1, Number(topK) || DEFAULT_MEMORY_TOP_K);
    const scoreNum = Number(minScore);
    const score =
      Number.isFinite(scoreNum) && scoreNum >= 0 && scoreNum <= 1
        ? scoreNum
        : DEFAULT_MEMORY_MIN_SCORE;
    setExtractionInterval(String(interval));
    setVerbatimWindow(String(window));
    setTopK(String(k));
    setMinScore(String(score));
    await Promise.all([
      setSetting("extraction_interval", String(interval)),
      setSetting("verbatim_window", String(window)),
      setSetting("embedding_model", embeddingModel.trim()),
      setSetting("memory_top_k", String(k)),
      setSetting("memory_min_score", String(score)),
    ]);
    setSaved(true);
    setTimeout(() => setSaved(false), 2000);
  };

  return (
    <section
      className="rounded-[var(--radius-lg)] border p-5"
      style={{ borderColor: "var(--color-border)", backgroundColor: "var(--color-surface)" }}
    >
      <h2 className="mb-1 font-[var(--font-display)] text-lg">{t("sections.memory")}</h2>
      <p className="mb-4 text-xs" style={{ color: "var(--color-text-faint)" }}>
        {t("memory.subtitle")}
      </p>

      <div className="flex flex-col gap-4 sm:flex-row sm:gap-10">
        <label className="flex flex-col gap-1 text-sm">
          <span className="flex items-center gap-1">
            {t("memory.extractionInterval")}
            <FieldHelp text={t("memory.help.extractionInterval")} />
          </span>
          <input
            type="number"
            min={1}
            className="w-32 rounded-[var(--radius-sm)] border px-2 py-1.5"
            style={inputStyle}
            value={extractionInterval}
            onChange={(e) => setExtractionInterval(e.target.value)}
          />
        </label>
        <label className="flex flex-col gap-1 text-sm">
          <span className="flex items-center gap-1">
            {t("memory.verbatimWindow")}
            <FieldHelp text={t("memory.help.verbatimWindow")} />
          </span>
          <input
            type="number"
            min={4}
            className="w-32 rounded-[var(--radius-sm)] border px-2 py-1.5"
            style={inputStyle}
            value={verbatimWindow}
            onChange={(e) => setVerbatimWindow(e.target.value)}
          />
        </label>
      </div>

      <h3 className="mb-1 mt-6 text-sm font-medium">{t("memory.embedding.title")}</h3>
      <p className="mb-3 text-xs" style={{ color: "var(--color-text-faint)" }}>
        {t("memory.embedding.subtitle")}
      </p>
      <div className="flex flex-col gap-4 sm:flex-row sm:gap-10">
        <label className="flex flex-col gap-1 text-sm">
          <span className="flex items-center gap-1">
            {t("memory.embedding.model")}
            <FieldHelp text={t("memory.help.embeddingModel")} />
          </span>
          <input
            className="w-56 rounded-[var(--radius-sm)] border px-2 py-1.5"
            style={inputStyle}
            value={embeddingModel}
            placeholder={t("memory.embedding.modelPlaceholder") ?? ""}
            onChange={(e) => setEmbeddingModel(e.target.value)}
          />
        </label>
        <label className="flex flex-col gap-1 text-sm">
          <span className="flex items-center gap-1">
            {t("memory.embedding.topK")}
            <FieldHelp text={t("memory.help.topK")} />
          </span>
          <input
            type="number"
            min={1}
            className="w-32 rounded-[var(--radius-sm)] border px-2 py-1.5"
            style={inputStyle}
            value={topK}
            onChange={(e) => setTopK(e.target.value)}
          />
        </label>
        <label className="flex flex-col gap-1 text-sm">
          <span className="flex items-center gap-1">
            {t("memory.embedding.minScore")}
            <FieldHelp text={t("memory.help.minScore")} />
          </span>
          <input
            type="number"
            min={0}
            max={1}
            step={0.05}
            className="w-32 rounded-[var(--radius-sm)] border px-2 py-1.5"
            style={inputStyle}
            value={minScore}
            onChange={(e) => setMinScore(e.target.value)}
          />
        </label>
      </div>

      <div className="mt-4 flex items-center gap-3">
        <button
          type="button"
          onClick={() => void handleSave()}
          className="rounded-[var(--radius-sm)] px-3 py-1.5 text-sm font-medium"
          style={{ backgroundColor: "var(--color-accent)", color: "var(--color-accent-contrast)" }}
        >
          {t("actions.save", { ns: "common" })}
        </button>
        {saved && (
          <span className="text-xs" style={{ color: "var(--color-success)" }}>
            {t("memory.saved")}
          </span>
        )}
      </div>
    </section>
  );
}

import { execute, newId, nowIso, query } from "../database";

export type EmbeddingKind = "fact" | "summary" | "message" | "lore";

export interface StoredEmbedding {
  id: string;
  /** Null for chat-agnostic rows (kind 'lore'). */
  chatId: string | null;
  kind: EmbeddingKind;
  refId: string;
  /** The exact text that was embedded — compared against the current
   * source text to detect stale rows needing re-embedding. */
  text: string;
  model: string;
  dims: number;
  /** base64-encoded little-endian f32 array (see memory/vector.ts). */
  vector: string;
  createdAt: string;
}

interface EmbeddingRow {
  id: string;
  chat_id: string | null;
  kind: EmbeddingKind;
  ref_id: string;
  text: string;
  model: string;
  dims: number;
  vector: string;
  created_at: string;
}

function toEmbedding(row: EmbeddingRow): StoredEmbedding {
  return {
    id: row.id,
    chatId: row.chat_id,
    kind: row.kind,
    refId: row.ref_id,
    text: row.text,
    model: row.model,
    dims: row.dims,
    vector: row.vector,
    createdAt: row.created_at,
  };
}

export async function listEmbeddings(
  chatId: string,
  kind: EmbeddingKind,
): Promise<StoredEmbedding[]> {
  const rows = await query<EmbeddingRow>(
    "SELECT * FROM embeddings WHERE chat_id = $1 AND kind = $2",
    [chatId, kind],
  );
  return rows.map(toEmbedding);
}

export async function upsertEmbedding(
  chatId: string | null,
  kind: EmbeddingKind,
  refId: string,
  text: string,
  model: string,
  dims: number,
  vector: string,
): Promise<void> {
  await execute(
    `INSERT INTO embeddings (id, chat_id, kind, ref_id, text, model, dims, vector, created_at)
     VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9)
     ON CONFLICT (kind, ref_id)
     DO UPDATE SET text = $5, model = $6, dims = $7, vector = $8`,
    [newId(), chatId, kind, refId, text, model, dims, vector, nowIso()],
  );
}

/** Removes rows whose source (fact/message/…) no longer exists. */
export async function deleteEmbeddingsByRefIds(
  kind: EmbeddingKind,
  refIds: string[],
): Promise<void> {
  for (const refId of refIds) {
    await execute("DELETE FROM embeddings WHERE kind = $1 AND ref_id = $2", [kind, refId]);
  }
}

/** Fetches rows for a specific set of source ids (used for lorebook
 * entries, which aren't chat-scoped). Chunked to stay under SQLite's
 * parameter limit. */
export async function listEmbeddingsByRefIds(
  kind: EmbeddingKind,
  refIds: string[],
): Promise<StoredEmbedding[]> {
  const out: StoredEmbedding[] = [];
  const CHUNK = 200;
  for (let i = 0; i < refIds.length; i += CHUNK) {
    const chunk = refIds.slice(i, i + CHUNK);
    const placeholders = chunk.map((_, j) => `$${j + 2}`).join(", ");
    const rows = await query<EmbeddingRow>(
      `SELECT * FROM embeddings WHERE kind = $1 AND ref_id IN (${placeholders})`,
      [kind, ...chunk],
    );
    out.push(...rows.map(toEmbedding));
  }
  return out;
}

/** Everything embedded for a chat — the reindex path re-embeds these rows'
 * stored texts with the current model. */
export async function listAllChatEmbeddings(chatId: string): Promise<StoredEmbedding[]> {
  const rows = await query<EmbeddingRow>("SELECT * FROM embeddings WHERE chat_id = $1", [chatId]);
  return rows.map(toEmbedding);
}

import { invoke } from "@tauri-apps/api/core";

import { logUsage } from "../db/repositories/usageRepo";
import { estimateTokens } from "../prompt/tokenEstimate";
import type { ConnectionConfig } from "./types";

export interface EmbedResult {
  model: string;
  vectors: number[][];
}

/** Embeds a batch of texts via the connection's provider (Gemini/OpenAI;
 * Claude has no embedding API and rejects). Returns the embedding model id
 * plus one vector per text, in input order. `model` overrides the
 * per-provider default (the `embedding_model` setting). */
export async function embedTexts(
  connection: ConnectionConfig,
  texts: string[],
  model?: string | null,
): Promise<EmbedResult> {
  const [usedModel, vectors] = await invoke<[string, number[][]]>("embed_texts", {
    connectionId: connection.id,
    provider: connection.provider,
    baseUrl: connection.baseUrl,
    model: model ?? null,
    texts,
  });
  const inputTokens = texts.reduce((sum, t) => sum + estimateTokens(t), 0);
  void logUsage("embedding", connection.id, inputTokens, 0).catch(() => {});
  return { model: usedModel, vectors };
}

/** Memory engine orchestration (plan §6.3): decides *when* to run an
 * extraction/summarization pass and makes sure at most one job runs per
 * chat at a time. The actual LLM work lives in `extractor.ts` /
 * `summarizer.ts`; both already swallow their own errors, so a failure
 * here never surfaces to the chat UI — it's logged and simply retried the
 * next time `scheduleMemoryWork` is called (next assistant message). */

import { getConnection } from "../db/repositories/connectionsRepo";
import {
  getChat,
  setLastExtractedMessageId,
  setLastSummarizedMessageId,
} from "../db/repositories/chatsRepo";
import { listChatMembers } from "../db/repositories/chatMembersRepo";
import { getCharacter } from "../db/repositories/charactersRepo";
import { listMessages, type Message } from "../db/repositories/messagesRepo";
import { getSetting } from "../db/repositories/settingsRepo";
import type { ConnectionConfig } from "../providers/types";
import { DEFAULT_VERBATIM_WINDOW } from "../prompt/promptBuilder";
import { listActivatableEntriesForMembers } from "../db/repositories/lorebooksRepo";
import {
  syncFactEmbeddings,
  syncLoreEmbeddings,
  syncMessageChunkEmbeddings,
} from "./embeddingsEngine";
import { runExtraction, type TranscriptChatMessage } from "./extractor";
import { runSummarization, type TranscriptMessage } from "./summarizer";

export const DEFAULT_EXTRACTION_INTERVAL = 10;
/** How many messages must have scrolled past the verbatim window,
 * unsummarized, before a summarization pass is queued. Fixed per plan
 * §6.3 (only the extraction interval and verbatim window are settings). */
export const SUMMARIZE_TRIGGER_THRESHOLD = 10;

interface QueueEntry {
  running: boolean;
  pendingRerun: boolean;
}

const queues = new Map<string, QueueEntry>();

/** Maps messages to transcript entries for the extractor, stamping
 * `speakerName` from `Message.characterId` via a chatId->name lookup built
 * once per pass (plan §M10) — solo chats get an empty map and every message
 * falls back to the "AI"/"Hráč" label as before. */
function toApiMessages(messages: Message[], memberNames: Map<string, string>): TranscriptChatMessage[] {
  return messages
    .filter((m) => m.role === "user" || m.role === "assistant")
    .map((m) => ({
      role: m.role,
      content: m.content,
      speakerName: m.characterId ? (memberNames.get(m.characterId) ?? null) : null,
    }));
}

/** Same speaker-name stamping for the summarizer's `Message[]`-shaped
 * input. */
function withSpeakerNames(messages: Message[], memberNames: Map<string, string>): TranscriptMessage[] {
  return messages.map((m) => ({
    ...m,
    speakerName: m.characterId ? (memberNames.get(m.characterId) ?? null) : null,
  }));
}

async function readNumberSetting(key: string, fallback: number): Promise<number> {
  const raw = await getSetting(key);
  const parsed = raw ? Number(raw) : NaN;
  return Number.isFinite(parsed) && parsed > 0 ? parsed : fallback;
}

async function resolveExtractionConnection(
  extractionConnectionId: string | null,
  connectionId: string | null,
): Promise<ConnectionConfig | null> {
  const id = extractionConnectionId ?? connectionId;
  if (!id) return null;
  return getConnection(id);
}

/** One pass of "check both triggers and run whatever's due". Re-reads
 * fresh state from the DB every time it's invoked, so it's naturally
 * idempotent — running it twice in a row when nothing changed is a no-op
 * the second time. */
async function runDueWork(chatId: string): Promise<void> {
  const chat = await getChat(chatId);
  if (!chat) return;
  const messages = await listMessages(chatId);
  if (messages.length === 0) return;

  const [extractionInterval, verbatimWindow, members] = await Promise.all([
    readNumberSetting("extraction_interval", DEFAULT_EXTRACTION_INTERVAL),
    readNumberSetting("verbatim_window", DEFAULT_VERBATIM_WINDOW),
    listChatMembers(chatId),
  ]);
  const memberCharacterIds = members.map((m) => m.characterId);
  // Built once per pass (not per message) — used to stamp speaker names on
  // the extraction/summarization transcripts (plan §M10).
  const memberNames = new Map<string, string>();
  await Promise.all(
    members.map(async (m) => {
      const character = await getCharacter(m.characterId);
      if (character) memberNames.set(m.characterId, character.name);
    }),
  );

  // --- Extraction: messages since last_extracted_message_id ---
  const lastExtractedIdx = chat.lastExtractedMessageId
    ? messages.findIndex((m) => m.id === chat.lastExtractedMessageId)
    : -1;
  const newSinceExtraction = messages.slice(lastExtractedIdx + 1);
  if (newSinceExtraction.length >= extractionInterval) {
    const connection = await resolveExtractionConnection(
      chat.extractionConnectionId,
      chat.connectionId,
    );
    if (connection) {
      await runExtraction(chatId, connection, toApiMessages(newSinceExtraction, memberNames));
      await setLastExtractedMessageId(chatId, messages[messages.length - 1].id);
    }
  }

  // --- Summarization: unmerged messages older than the verbatim window ---
  const lastSummarizedIdx = chat.lastSummarizedMessageId
    ? messages.findIndex((m) => m.id === chat.lastSummarizedMessageId)
    : -1;
  const foldableEnd = messages.length - verbatimWindow; // exclusive upper bound
  const toFold =
    foldableEnd > lastSummarizedIdx + 1 ? messages.slice(lastSummarizedIdx + 1, foldableEnd) : [];
  let folded: Message[] = [];
  if (toFold.length >= SUMMARIZE_TRIGGER_THRESHOLD) {
    const connection = chat.connectionId ? await getConnection(chat.connectionId) : null;
    if (connection) {
      await runSummarization(chatId, connection, withSpeakerNames(toFold, memberNames));
      await setLastSummarizedMessageId(chatId, toFold[toFold.length - 1].id);
      folded = toFold;
    }
  }

  // --- Embeddings (M7/M8) ---
  // Facts and lore sync every pass, but only call the embedding API when a
  // row is new or was edited since its last embedding — so manual edits
  // from the memory panel get picked up too. Message chunks are embedded
  // exactly once, right after their messages were folded into the summary.
  try {
    const connection = await resolveExtractionConnection(
      chat.extractionConnectionId,
      chat.connectionId,
    );
    await syncFactEmbeddings(chatId, connection);
    if (folded.length > 0) {
      await syncMessageChunkEmbeddings(chatId, connection, folded);
    }
    const loreEntries = await listActivatableEntriesForMembers(
      memberCharacterIds.length > 0 ? memberCharacterIds : [chat.characterId],
      chatId,
    );
    await syncLoreEmbeddings(connection, loreEntries);
  } catch (err) {
    console.warn("embedding sync failed", err);
  }
}

async function drainQueue(chatId: string, entry: QueueEntry): Promise<void> {
  try {
    await runDueWork(chatId);
  } catch (err) {
    // Belt and suspenders: extractor/summarizer already catch their own
    // errors, but a DB read/write here (e.g. getChat) could still throw.
    console.warn("memory engine job failed", err);
  } finally {
    entry.running = false;
    if (entry.pendingRerun) {
      entry.pendingRerun = false;
      scheduleMemoryWork(chatId);
    }
  }
}

/** Queues a "check and run due memory work" pass for a chat. Call this
 * after an assistant message is finalized (plan §6.3). Fire-and-forget by
 * design — never awaited by the chat flow, never throws, and coalesces
 * concurrent triggers into a single rerun per chat so at most one job runs
 * at a time. */
export function scheduleMemoryWork(chatId: string): void {
  const entry = queues.get(chatId) ?? { running: false, pendingRerun: false };
  queues.set(chatId, entry);

  if (entry.running) {
    entry.pendingRerun = true;
    return;
  }
  entry.running = true;
  void drainQueue(chatId, entry);
}

